import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"39. Change Of Shift Allowance","description":"","frontmatter":{"title":"39. Change Of Shift Allowance","eba":"Allied Health Professionals 2021-2026","topics":["hours","shift-work","allowances"]},"headers":[],"relativePath":"ebas/allied-health/allowances/39-change-of-shift-allowance.md","filePath":"ebas/allied-health/allowances/39-change-of-shift-allowance.md"}'),s={name:"ebas/allied-health/allowances/39-change-of-shift-allowance.md"};function l(h,e,i,c,r,f){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_39-change-of-shift-allowance" tabindex="-1">39. Change Of Shift Allowance <a class="header-anchor" href="#_39-change-of-shift-allowance" aria-label="Permalink to &quot;39. Change Of Shift Allowance&quot;">​</a></h1><p><strong>39.1</strong> An Employee who changes from working on one shift (first shift) to working on another shift (second shift) and the time of commencement of the second shift differs by four (4) hours or more from the first shift, will be paid a change of shift allowance of the amount specified in <a href="/eba/ebas/allied-health/appendices/3-allowances-and-top-of-band-payments.html">Appendix 3</a> of this Agreement for each such change except as provided at subclauses 39.2 and 39.3 below.</p><p><strong>39.2</strong> Exception – two contracted positions The change of shift allowance is not payable where an Employee holds two (2) contemporaneous, contracted, different positions with the same Employer and moving between those positions results in a change of shift pattern that would ordinarily invoke a change of shift allowance payment.</p><p><strong>39.3</strong> Exceptions – Employee requests change and 2 weeks off duty The change of shift allowance is not payable where:</p><p><strong>(a)</strong> the Employee requests a change to the roster which creates a change of shift as described in subclause 39.1; or</p><p><strong>(b)</strong> there is at least two (2) weeks of continuous approved leave between the relevant shifts which creates a change of shift as described in subclause 39.1.</p><p><strong>39.4</strong> The allowances payable pursuant to this clause 39 will be calculated to the nearest five (5) cents, portions of a cent being disregarded.</p>',7)])])}const g=a(s,[["render",l]]);export{d as __pageData,g as default};
